	"com/nikitatrainings/view/View1.view.xml":'<mvc:View xmlns:core="sap.ui.core" xmlns:mvc="sap.ui.core.mvc" xmlns="sap.m" controllerName="com.nikitatrainings.controller.View1"\n\txmlns:html="http://www.w3.org/1999/xhtml"><Page title="View 1"><content><SearchField id="idSearch" search="onSearch" liveChange="onSearch"></SearchField><List items="{ path: \'/ProductSet\'\n\t\t\t}" mode="SingleSelectMaster" itemPress="onItemSelect" id="idList"\n\t\t\t\t  selectionChange="onSelectChange"><items><ObjectListItem intro="{Category}" title="{Name}" icon="sap-icon://product"\n\t\t\t\t\t\t\t\t    number="{Price}" numberUnit="{CurrencyCode}"><firstStatus><ObjectStatus text="{TypeCode}" state="Success"></ObjectStatus></firstStatus></ObjectListItem></items><infoToolbar><OverflowToolbar active="{/deviceConnected}" ><Label text="{/onlineOrOfflineStatusText}"></Label></OverflowToolbar></infoToolbar></List></content><footer><Toolbar></Toolbar></footer><headerContent><Button icon="sap-icon://action" press="onNext"></Button></headerContent></Page></mvc:View>',
	"com/nikitatrainings/view/View2.view.xml":'<mvc:View xmlns:core="sap.ui.core" xmlns:mvc="sap.ui.core.mvc" xmlns="sap.m" controllerName="com.nikitatrainings.controller.View2"\n\txmlns:f="sap.ui.layout.form" xmlns:html="http://www.w3.org/1999/xhtml"><Page title="View 2"  showNavButton="{=${local>/isPhone} === true? true:false}" navButtonPress="onNavBack"><content><ObjectHeader title="{Name}" intro="{Category}" \n\t\t\t              number="{Price}" numberUnit="{CurrencyCode}" icon="sap-icon://product"></ObjectHeader><IconTabBar><items><IconTabFilter text="Additional Info" key="" icon="sap-icon://home"><content><f:SimpleForm><f:content><Label text="Supplier Id"></Label><Text text="{SupplierId}"></Text><Label text="Type Code"></Label><Text text="{TypeCode}"></Text><Label text="Unit"></Label><Text text="{MeasureUnit}"></Text></f:content></f:SimpleForm></content></IconTabFilter><IconTabFilter text="Suppliers" key="" icon="sap-icon://supplier"><content><core:Fragment fragmentName="com.nikitatrainings.fragments.supplierTable" type="XML"></core:Fragment></content></IconTabFilter><IconTabFilter text="Cities" key="" icon="sap-icon://arrow-down"><Select items="{local>/cities}"><core:Item key="{local>name}" text="{local>name}"></core:Item></Select><ComboBox items="{local>/cities}"><core:Item key="{name}" text="{name}"></core:Item></ComboBox><MultiComboBox items="{local>/cities}"><core:Item key="{local>name}" text="{local>name}"></core:Item></MultiComboBox></IconTabFilter></items></IconTabBar></content><footer><Toolbar><ToolbarSpacer /><Button text="Save" press="onSave" type="Accept"></Button><Button text="Cancel" press="onCancel" type="Reject"></Button></Toolbar></footer></Page></mvc:View>',
